243	
244	    // First run: commits + bookmarks succeed; push-app we
245	    // simulate via a second step rather than trying to force a
246	    // real push failure (which jj makes hard — local bare-git
247	    // remotes accept almost anything). Instead, split the run
248	    // using --no-finalize on the second pass.
249	    let mut params1 = test_params("feat: resume", "resume body");
250	    params1.from = Some(Stage::Message);
251	    push_in(&fx.work, &params1).expect("first push run");
252	
253	    // After the full run, state file should be cleared and main
254	    // should be advanced in the app repo.
